import{_ as t,o as r,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"29A. Certificate Of Service","description":"","frontmatter":{"title":"29A. Certificate Of Service","eba":"Doctors in Training 2022-2026","topics":["leave","personal-leave","long-service-leave","employment","termination"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/29A-certificate-of-service.md","filePath":"ebas/doctors-in-training/doctor-employment/29A-certificate-of-service.md"}'),a={name:"ebas/doctors-in-training/doctor-employment/29A-certificate-of-service.md"};function n(c,e,s,p,f,l){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_29a-certificate-of-service" tabindex="-1">29A. Certificate Of Service <a class="header-anchor" href="#_29a-certificate-of-service" aria-label="Permalink to &quot;29A. Certificate Of Service&quot;">​</a></h1><p><strong>29A.1</strong> The Health Service will record the following particulars in respect of each Doctor:</p><p><strong>(a)</strong> Date of commencement of employment;</p><p><strong>(b)</strong> Date of termination of employment;</p><p><strong>(c)</strong> Total period of service (years and months);</p><p><strong>(d)</strong> Long Service Leave taken during the period of service, or payments made in lieu thereof; and</p><p><strong>(e)</strong> Accumulated personal/carer’s leave at termination.</p><p><strong>29A.2</strong> On request, a copy of the record will be furnished to the Doctor.</p><p><strong>29A.3</strong> A certificate in the form set out in <a href="/eba/ebas/doctors-in-training/appendices/3-template-certificate-of-service.html">Appendix 3</a> will be acceptable.</p><p><strong>29A.4</strong> A Doctor may request a document from their Employer which provides ‘Employment Information’ that can be used for the sole purpose of enabling their classification to be recognised by another Employer.</p><p>Plain language terms: service certificate.</p>',11)])])}const g=t(a,[["render",n]]);expor